const { ApolloServer, gql } = require('apollo-server-express');
const express = require('express');
const { v4: uuidv4 } = require('uuid');

// Mock database
const users = [
  { id: '1', name: 'John Doe', email: 'john@example.com', age: 30 },
  { id: '2', name: 'Jane Smith', email: 'jane@example.com', age: 25 },
  { id: '3', name: 'Bob Johnson', email: 'bob@example.com', age: 35 },
  { id: '4', name: 'Alice Brown', email: 'alice@example.com', age: 28 },
  { id: '5', name: 'Charlie Wilson', email: 'charlie@example.com', age: 32 }
];

// Schema
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    email: String!
    age: Int!
  }

  type Query {
    users(ids: [ID!]!): [User!]!
    user(id: ID!): User
  }
`;

// Resolvers
const resolvers = {
  Query: {
    users: async (_, { ids }) => {
      // Validate input - check for reasonable limits
      if (ids.length > 100) {
        throw new Error('Maximum 100 user IDs allowed per request');
      }
      
      // Validate that all IDs are valid
      const validIds = ids.filter(id => {
        if (typeof id !== 'string') return false;
        return users.some(user => user.id === id);
      });
      
      // Return users in the same order as requested
      return validIds.map(id => users.find(user => user.id === id));
    },
    user: async (_, { id }) => {
      return users.find(user => user.id === id);
    }
  }
};

// Create Apollo Server
const server = new ApolloServer({
  typeDefs,
  resolvers,
  // Security: Disable introspection in production
  introspection: process.env.NODE_ENV !== 'production',
  // Security: Disable playground in production
  playground: process.env.NODE_ENV !== 'production',
  // Security: Add request validation
  validationRules: [
    // Add custom validation rules here if needed
  ],
  // Security: Add context for request processing
  context: ({ req }) => {
    // Add authentication and authorization checks here
    return {
      // Add user context if authenticated
      user: req.user || null
    };
  }
});

// Create Express app
const app = express();

// Start server
async function startServer() {
  await server.start();
  server.applyMiddleware({ app, path: '/graphql' });
  
  const PORT = process.env.PORT || 4000;
  app.listen(PORT, () => {
    console.log(`Server running at http://localhost:${PORT}${server.graphqlPath}`);
  });
}

startServer().catch(error => {
  console.error('Error starting server:', error);
});